#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <getopt.h>
#include <assert.h>
#include <omp.h>

#include "common.h"

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

static void lud_diagonal(float *m, int matrix_dim, int offset)
{
    int i, j;
    float shadow[BLOCK_SIZE][BLOCK_SIZE];

    int array_offset = offset * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            shadow[i][j] = m[array_offset + j];
        }
        array_offset += matrix_dim;
    }

    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        #pragma omp parallel for private(j) shared(shadow,i)
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            float sum1 = 0.0f;
            for (int k = 0; k < i; k++) {
                sum1 += shadow[j][k] * shadow[k][i];
            }
            shadow[j][i] = (shadow[j][i] - sum1) / shadow[i][i];
        }

        #pragma omp parallel for private(j) shared(shadow,i)
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            float sum2 = 0.0f;
            for (int k = 0; k < i + 1; k++) {
                sum2 += shadow[i + 1][k] * shadow[k][j];
            }
            shadow[i + 1][j] = shadow[i + 1][j] - sum2;
        }
    }

    array_offset = (offset + 1) * matrix_dim + offset;
    for (i = 1; i < BLOCK_SIZE; i++) {
        for (j = 0; j < BLOCK_SIZE; j++) {
            m[array_offset + j] = shadow[i][j];
        }
        array_offset += matrix_dim;
    }
}

static void lud_perimeter(float *m, int matrix_dim, int offset)
{
    float dia[BLOCK_SIZE][BLOCK_SIZE];
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];

    int i, j, array_offset;

    int block_count = (matrix_dim - offset) / BLOCK_SIZE - 1;

    #pragma omp parallel for private(i,j,array_offset) shared(m,dia,peri_row,peri_col,offset,matrix_dim,block_count)
    for (int blockIdx = 0; blockIdx < block_count; blockIdx++) {
        int thread_x;

        // Load dia and perimeter row and column
        #pragma omp parallel for private(i) shared(dia,peri_row,peri_col,m,offset,matrix_dim,blockIdx)
        for (thread_x = 0; thread_x < BLOCK_SIZE * 2; thread_x++) {
            int idx;
            if (thread_x < BLOCK_SIZE) {
                idx = thread_x;
                array_offset = offset * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE / 2; i++) {
                    dia[i][idx] = m[array_offset + idx];
                    array_offset += matrix_dim;
                }
                array_offset = offset * matrix_dim + offset + (blockIdx + 1) * BLOCK_SIZE;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    peri_row[i][idx] = m[array_offset + idx];
                    array_offset += matrix_dim;
                }
            } else {
                idx = thread_x - BLOCK_SIZE;
                array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
                for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
                    dia[i][idx] = m[array_offset + idx];
                    array_offset += matrix_dim;
                }
                array_offset = (offset + (blockIdx + 1) * BLOCK_SIZE) * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    peri_col[i][idx] = m[array_offset + idx];
                    array_offset += matrix_dim;
                }
            }
        }

        // Compute peri_row
        #pragma omp parallel for private(i,j) shared(peri_row,dia)
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            for (i = 1; i < BLOCK_SIZE; i++) {
                for (j = 0; j < i; j++) {
                    peri_row[i][tx] -= dia[i][j] * peri_row[j][tx];
                }
            }
        }

        // Compute peri_col
        #pragma omp parallel for private(i,j) shared(peri_col,dia)
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < i; j++) {
                    peri_col[tx][i] -= peri_col[tx][j] * dia[j][i];
                }
                peri_col[tx][i] /= dia[i][i];
            }
        }

        // Write back peri_row
        array_offset = (offset + 1) * matrix_dim + offset + (blockIdx + 1) * BLOCK_SIZE;
        for (i = 1; i < BLOCK_SIZE; i++) {
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                m[array_offset + tx] = peri_row[i][tx];
            }
            array_offset += matrix_dim;
        }

        // Write back peri_col
        array_offset = (offset + (blockIdx + 1) * BLOCK_SIZE) * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                m[array_offset + tx] = peri_col[tx][i];
            }
            array_offset += matrix_dim;
        }
    }
}

static void lud_internal(float *m, int matrix_dim, int offset)
{
    int grid_dim = (matrix_dim - offset) / BLOCK_SIZE - 1;

    #pragma omp parallel for collapse(2) schedule(static)
    for (int block_y = 0; block_y < grid_dim; block_y++) {
        for (int block_x = 0; block_x < grid_dim; block_x++) {
            float peri_row[BLOCK_SIZE][BLOCK_SIZE];
            float peri_col[BLOCK_SIZE][BLOCK_SIZE];

            int global_row_id = offset + (block_y + 1) * BLOCK_SIZE;
            int global_col_id = offset + (block_x + 1) * BLOCK_SIZE;

            // Load peri_row and peri_col
            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    peri_row[ty][tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
                    peri_col[ty][tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];
                }
            }

            // Compute subtraction sum
            for (int ty = 0; ty < BLOCK_SIZE; ty++) {
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    float sum = 0.f;
                    for (int i = 0; i < BLOCK_SIZE; i++) {
                        sum += peri_col[ty][i] * peri_row[i][tx];
                    }
                    m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
                }
            }
        }
    }
}

void lud_cuda(float *m, int matrix_dim)
{
    int i = 0;
    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        lud_diagonal(m, matrix_dim, i);
        lud_perimeter(m, matrix_dim, i);
        lud_internal(m, matrix_dim, i);
    }
    lud_diagonal(m, matrix_dim, i);
}

int
main ( int argc, char *argv[] )
{
  printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);

  int matrix_dim = 32; 
  int opt, option_index=0;
  func_ret_t ret;
  const char *input_file = NULL;
  float *m, *mm;
  stopwatch sw;

  static int do_verify = 0;

  static struct option long_options[] = {
    {"input", 1, NULL, 'i'},
    {"size", 1, NULL, 's'},
    {"verify", 0, NULL, 'v'},
    {0,0,0,0}
  };

  while ((opt = getopt_long(argc, argv, "::vs:i:", 
                            long_options, &option_index)) != -1 ) {
    switch(opt){
    case 'i':
      input_file = optarg;
      break;
    case 'v':
      do_verify = 1;
      break;
    case 's':
      matrix_dim = atoi(optarg);
      printf("Generate input matrix internally, size =%d\n", matrix_dim);
      break;
    case '?':
      fprintf(stderr, "invalid option\n");
      break;
    case ':':
      fprintf(stderr, "missing argument\n");
      break;
    default:
      fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
	      argv[0]);
      exit(EXIT_FAILURE);
    }
  }

  if ( (optind < argc) || (optind == 1)) {
    fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
    exit(EXIT_FAILURE);
  }

  if (input_file) {
    printf("Reading matrix from file %s\n", input_file);
    ret = create_matrix_from_file(&m, input_file, &matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix from file %s\n", input_file);
      exit(EXIT_FAILURE);
    }
  } 
  else if (matrix_dim) {
    printf("Creating matrix internally size=%d\n", matrix_dim);
    ret = create_matrix(&m, matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix internally size=%d\n", matrix_dim);
      exit(EXIT_FAILURE);
    }
  }
  else {
    printf("No input file specified!\n");
    exit(EXIT_FAILURE);
  }

  if (do_verify){
    printf("Before LUD\n");
    matrix_duplicate(m, &mm, matrix_dim);
  }

  stopwatch_start(&sw);

  lud_cuda(m, matrix_dim);

  stopwatch_stop(&sw);
  printf("Time consumed(ms): %lf\n", 1000*get_interval_by_sec(&sw));

  if (do_verify){
    printf("After LUD\n");
    printf(">>>Verify<<<<\n");
    lud_verify(mm, m, matrix_dim); 
    free(mm);
  }

  free(m);

  return EXIT_SUCCESS;
}
